// Market-hours guard: only proceed during NYSE hours (Mon-Fri 09:30-16:00 ET)
const { checkMarketHours } = require('/home/node/.n8n/code/insiderbuying/market-hours-guard.js');
const { isMarketHours } = checkMarketHours(new Date());
if (!isMarketHours) return [];
return [{ json: { marketHours: true } }];

const { runSecMonitor } = require('/home/node/.n8n/code/insiderbuying/sec-monitor.js');
const _https = require('https');
const _http = require('http');
const { URL } = require('url');

function fetchFn(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const mod = u.protocol === 'https:' ? _https : _http;
    const reqOpts = { hostname: u.hostname, port: u.port, path: u.pathname + u.search, method: opts.method || 'GET', headers: { ...opts.headers } };
    if (opts.body) reqOpts.headers['Content-Type'] = reqOpts.headers['Content-Type'] || 'application/json';
    const req = mod.request(reqOpts, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: () => Promise.resolve(JSON.parse(body)), text: () => Promise.resolve(body) });
      });
    });
    req.on('error', reject);
    if (opts.body) req.write(typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body));
    req.end();
  });
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const filings = await runSecMonitor({ fetchFn, sleep, env: $env });
return filings.map(f => ({ json: f }));

